'use client'

import { ShoppingBag, Package, Truck, DollarSign, Search, Filter } from 'lucide-react'
import Link from 'next/link'
import Header from '@/components/Header'
import StatsCard from '@/components/StatsCard'
import { useAuth } from '@/hooks/use-auth'

export default function RetailerDashboard() {
  const { user } = useAuth()

  // Mock data - replace with real data from API
  const stats = [
    {
      icon: ShoppingBag,
      label: 'Total Orders Placed',
      value: '42',
      trend: { value: 8, isPositive: true },
      color: 'primary' as const,
    },
    {
      icon: Package,
      label: 'Pending Deliveries',
      value: '12',
      trend: { value: 3, isPositive: false },
      color: 'accent' as const,
    },
    {
      icon: DollarSign,
      label: 'Total Spent',
      value: '128,500 ETB',
      trend: { value: 15, isPositive: true },
      color: 'secondary' as const,
    },
    {
      icon: Truck,
      label: 'In Transit',
      value: '7',
      trend: { value: 2, isPositive: true },
      color: 'primary' as const,
    },
  ]

  const recentPurchases = [
    {
      id: '1',
      orderNumber: '#ORD-5678',
      product: 'ቲማቲም (Tomatoes)',
      quantity: 150,
      unit: 'KG',
      total: 3750,
      status: 'delivered' as const,
      date: new Date('2024-01-20'),
      farmer: 'አበበ ገ/መድህን Farm',
    },
    {
      id: '2',
      orderNumber: '#ORD-5677',
      product: 'ሽንኩርት (Onions)',
      quantity: 100,
      unit: 'KG',
      total: 3000,
      status: 'in_transit' as const,
      date: new Date('2024-01-19'),
      farmer: 'Green Valley Farms',
    },
    {
      id: '3',
      orderNumber: '#ORD-5676',
      product: 'ድንች (Potatoes)',
      quantity: 250,
      unit: 'KG',
      total: 3750,
      status: 'pending' as const,
      date: new Date('2024-01-18'),
      farmer: 'Rift Valley Agriculture',
    },
  ]

  const getStatusBadge = (status: string) => {
    const styles = {
      delivered: 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200',
      in_transit: 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200',
      pending: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200',
    }
    const labels = {
      delivered: 'Delivered',
      in_transit: 'In Transit',
      pending: 'Pending',
    }
    return (
      <span className={`px-2 py-1 rounded-full text-xs font-medium ${styles[status as keyof typeof styles]}`}>
        {labels[status as keyof typeof labels]}
      </span>
    )
  }

  return (
    <div className="min-h-screen bg-background">
      <Header />

      <main className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">
        {/* Page Header */}
        <div className="flex flex-col items-start justify-between gap-4 sm:flex-row sm:items-center">
          <div>
            <h1 className="text-3xl font-bold text-foreground">Retailer Dashboard</h1>
            <p className="mt-1 text-muted-foreground">
              Welcome back, {user?.full_name || user?.name}! Browse products and manage your orders.
            </p>
          </div>
          <Link
            href="/products"
            className="flex items-center gap-2 rounded-lg bg-primary px-6 py-3 text-sm font-semibold text-primary-foreground hover:bg-primary/90 transition-colors whitespace-nowrap"
          >
            <Search className="h-5 w-5" />
            Browse Products
          </Link>
        </div>

        {/* Stats Grid */}
        <div className="mt-8 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
          {stats.map((stat, index) => (
            <StatsCard
              key={index}
              icon={stat.icon}
              label={stat.label}
              value={stat.value}
              trend={stat.trend}
              color={stat.color}
            />
          ))}
        </div>

        {/* Recent Purchases Section */}
        <div className="mt-12">
          <div className="flex flex-col items-start justify-between gap-4 sm:flex-row sm:items-center">
            <div>
              <h2 className="text-2xl font-bold text-foreground">Recent Purchases</h2>
              <p className="mt-1 text-sm text-muted-foreground">Your recent orders from farmers</p>
            </div>
            <Link
              href="/orders"
              className="text-sm font-semibold text-primary hover:text-primary/90 transition-colors whitespace-nowrap"
            >
              View All Orders →
            </Link>
          </div>

          <div className="mt-6 overflow-hidden rounded-lg border border-border bg-card">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Order
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Product
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Farmer
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Quantity
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Total
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Status
                    </th>
                    <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      Date
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {recentPurchases.map((purchase) => (
                    <tr key={purchase.id} className="hover:bg-muted/50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <Link
                          href={`/orders/${purchase.id}`}
                          className="text-sm font-medium text-primary hover:text-primary/90"
                        >
                          {purchase.orderNumber}
                        </Link>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm font-medium text-foreground">{purchase.product}</div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm text-muted-foreground">{purchase.farmer}</div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm text-foreground">
                          {purchase.quantity} {purchase.unit}
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm font-medium text-foreground">{purchase.total} ETB</div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">{getStatusBadge(purchase.status)}</td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-sm text-muted-foreground">
                          {purchase.date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="mt-12 grid gap-4 sm:grid-cols-3">
          <Link
            href="/products"
            className="flex flex-col items-start gap-3 rounded-lg border border-border bg-card p-6 hover:shadow-lg transition-shadow"
          >
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10 text-primary">
              <Search className="h-5 w-5" />
            </div>
            <h3 className="font-semibold text-foreground">Browse Products</h3>
            <p className="text-sm text-muted-foreground">Find fresh produce from verified farmers</p>
          </Link>

          <Link
            href="/orders"
            className="flex flex-col items-start gap-3 rounded-lg border border-border bg-card p-6 hover:shadow-lg transition-shadow"
          >
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-accent/10 text-accent">
              <Package className="h-5 w-5" />
            </div>
            <h3 className="font-semibold text-foreground">Track Orders</h3>
            <p className="text-sm text-muted-foreground">Monitor your order status and deliveries</p>
          </Link>

          <Link
            href="/transport"
            className="flex flex-col items-start gap-3 rounded-lg border border-border bg-card p-6 hover:shadow-lg transition-shadow"
          >
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-secondary/10 text-secondary">
              <Truck className="h-5 w-5" />
            </div>
            <h3 className="font-semibold text-foreground">Shipment Tracking</h3>
            <p className="text-sm text-muted-foreground">View real-time delivery updates</p>
          </Link>
        </div>
      </main>
    </div>
  )
}
